// 공통코드 조회 (전산 담당자 조회 후 등록점소 셋팅)
//-------------------------------------------------------------------------
scwin.getManager = async function () {
  // 데이타셋 초기화 필요
  ds_manager.removeAll();

  //	var pCode = '<%=empNo%>' ;
  var pCode = scwin.empNo;

  // SELECT 절 
  var param1 = "CD_NM  as COL1 , CD  as COL2 , ''  as COL3 , ''  as COL4 , ''  as COL5 , ''  as COL6 , ''  as COL7 , ''  as COL8 , ''  as COL9 , ''  as COL10";

  // 대상테이블 	
  var param2 = " TB_ZZ002 ";

  // 조건절
  var param3 = "AND GRP_CD = 'BRL06' AND USE_YN='1' AND CD = '" + pCode + "' "; //크나우프전산담당자

  var param4 = "CD";

  //	ds_empNo.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
  //	ds_empNo.Reset();

  // FI624 (증빙관리권한) - 01: user01, 02: user31, 03: user32, 04: user33, 05: user34, 06: user35, 07: user36, 08: user37
  // 2025-10-02 : 세무조사시에만 사용하는 계정으로 , 세무조사 인원이 조회시 보이지 않아야 하는 부분으로 구현 필요

  const strParam = {
    sysCd: "CommonEBC" // 시스템코드
    ,

    queryId: "dinymicQueryTest" // 쿼리ID
    ,

    param1: param1 // SELECT
    ,

    param2: param2 // 대상테이블
    ,

    param3: param3 // 조건절
    ,

    param4: param4 // CD
  };

  //데이터셋에 정보설정
  ds_commonCode.setJSON(strParam);
  await $c.sbm.execute($p, sbm_searchCommon);
};
scwin.sbm_searchCommon_submitdone = function (e) {
  if (e.responseJSON.GAUCE[0]) {
    ds_manager.insertRow();
    ds_manager.setRowJSON(0, e.responseJSON.GAUCE[0]);
  }
  scwin.f_lobranCdControl();
  scwin.f_bConfirmControl();
};
scwin.f_lobranCdControl = function () {
  if (ds_manager.getTotalRow() > 0) {
    ed_regBranCd.setValue("");
    ed_regBranNm.setValue("");
  } else {
    ed_regBranCd.setValue(scwin.lobranCd);
    ed_regBranNm.setValue(scwin.lobranNm);
    $c.gus.cfDisableObjects($p, [ed_regBranCd, ed_regBranNm, btn_PopUp3]);
  }
};
scwin.f_bConfirmControl = function () {
  var confirmYn = lc_confirmYn.getValue();
  if (ds_manager.getTotalRow() > 0) {
    if (confirmYn == "0") {
      $c.gus.cfEnableObjects($p, [btn_confirm]);
    } else {
      $c.gus.cfDisableObjects($p, [btn_confirm]);
    }
  } else {
    $c.gus.cfDisableObjects($p, [btn_confirm]);
  }
};

/* 확정처리 */
scwin.f_Confirm = async function () {
  if (lc_amtGb.getValue() == "") {
    $c.win.alert($p, "예외운송 또는 휴일운송을 선택 후 미확정 내역을 조회하시길 바랍니다.");
    return;
  }
  // TODO ::
  if (ds_master.getTotalRow() != 0) {
    var cnt = ds_master.getTotalRow();
    var total = gr_master.getFooterData("fSellAmt");
    var msg = $c.gus.cfInsertComma($p, total) + "원에 대해 확정처리 하시겠습니까? (" + $c.gus.cfInsertComma($p, cnt) + "건)";
    var rtn = await $c.win.confirm($p, msg);
    if (rtn) {
      ds_Query.set("clntNo", ed_clntNo.getValue());
      ds_Query.set("bizLongCd", ed_bizLongCd.getValue());
      ds_Query.set("odrDtFrom", ed_srchWrkStDt.getValue());
      ds_Query.set("odrDtTo", ed_srchWrkEndDt.getValue());
      ds_Query.set("amtGb", lc_amtGb.getValue() == "all" ? "" : lc_amtGb.getValue());
      ds_Query.set("wrkPlCd", "");
      ds_Query.set("lobranCd", ed_regBranCd.getValue());
      ds_Query.set("confirmYn", lc_confirmYn.getValue() == "all" ? "" : lc_confirmYn.getValue());
      ds_Query.set("odrNo", ed_odrNo.getValue());
      ds_Query.set("mchtOdrNo", ed_mchtOdrNo.getValue());
      $c.sbm.execute($p, sbm_confirm);
    }
  } else {
    $c.gus.cfAlertMsg($p, "확정처리할 데이터가 없습니다.");
    return;
  }
};

/* 저장 */
scwin.f_Save = async function () {
  // 필수입력사항 확인
  // 		if ( !cfValidate([gr_master])) {
  // 			return;
  // 		}
  // 변경된 사항이 있는지 확인.
  if (ds_master.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, "변경된 사항이 없습니다.");
    return;
  }
  var msg = "저장하시겠습니까?";
  let rtn = await $c.win.confirm($p, msg);
  if (rtn) {
    // 확정된 내역은 삭제할수없다.
    var confirmCnt = 0;
    for (var i = 0; i < ds_master.getTotalRow(); i++) {
      if (ds_master.getRowStatus(i) == "D") {
        // 삭제건에 한해서 확정유무 체크
        if (ds_master.getCellData(i, "confirmYn") == "1") {
          confirmCnt++;
        }
      }
    }
    if (confirmCnt > 0) {
      $c.win.alert($p, "확정된 건은 변경할 수 없습니다.");
      return;
    }
    var cnt = 0;
    ds_save.removeAll();
    for (var i = 0; i < ds_master.getTotalRow(); i++) {
      if (ds_master.getRowStatus(i) != "R") {
        ds_save.setRowJSON(cnt, ds_master.getRowJSON(i));
        if (ds_master.getRowStatus(i) == "D") ds_save.modifyRowStatus(cnt, "D");
        cnt++;
      }
    }
    $c.sbm.execute($p, sbm_save);
  }
};

/* 조회 */
scwin.f_Retrieve = async function () {
  // 거래처 선택 확인
  if ($c.gus.cfIsNull($p, ed_clntNo.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, new Array("거래처"));
    ed_clntNo.focus();
    return false;
  }
  if (ed_srchWrkStDt.getValue() == "") {
    await $c.win.alert($p, "작업 조회 시작일자은(는) 필수 입력 항목입니다.");
    ed_srchWrkStDt.focus();
    return;
  }
  if (ed_srchWrkEndDt.getValue() == "") {
    await $c.win.alert($p, "작업 조회 종료일자은(는) 필수 입력 항목입니다.");
    ed_srchWrkEndDt.focus();
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_srchWrkStDt.getValue(), ed_srchWrkEndDt.getValue())) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ed_srchWrkStDt.focus();
    return;
  }
  ds_Query.set("clntNo", ed_clntNo.getValue());
  ds_Query.set("bizLongCd", ed_bizLongCd.getValue());
  ds_Query.set("odrDtFrom", ed_srchWrkStDt.getValue());
  ds_Query.set("odrDtTo", ed_srchWrkEndDt.getValue());
  ds_Query.set("amtGb", lc_amtGb.getValue() == "all" ? "" : lc_amtGb.getValue());
  ds_Query.set("wrkPlCd", "");
  ds_Query.set("lobranCd", ed_regBranCd.getValue());
  ds_Query.set("confirmYn", lc_confirmYn.getValue() == "all" ? "" : lc_confirmYn.getValue());
  ds_Query.set("odrNo", ed_odrNo.getValue());
  ds_Query.set("mchtOdrNo", ed_mchtOdrNo.getValue());
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  debugger;
  $c.gus.cfEnableObjects($p, [udc_button, btn_DeleteAllRow, btn_save]); // , btn_UndoRow
  if (ds_master.getTotalRow() == 0) {
    $c.win.alert($p, "조회된 데이터가 없습니다.");
    eb_total.setValue("0");
    return;
  }
  eb_total.setValue(ds_master.getTotalRow());
  ds_master.modifyAllStatus("R");
  for (var i = 0; i < ds_master.getTotalRow(); i++) {
    if (ds_master.getRowStatus(i) == "R") gr_master.setRowReadOnly(i, true);
  }
  gr_master.setFocusedCell(0, 0);
};

