scwin.gr_master_onviewchange = function (info) {
  row = info.rowIndex;
  if (info.colIndex == 0) {
    var odrNo = ds_master.getCellData(row, "odrNo");
    var mchtOdrNo = ds_master.getCellData(row, "mchtOdrNo");
    if (ds_master.getCellData(row, "amtGb") == "2") {
      // 휴일운송일 경우 금액 오더정보 재조회
      ds_master.setCellData(row, "sellAmt", "0");
      if (odrNo != "") {
        scwin.f_openGridPopup(row, "1");
      } else if (mchtOdrNo != "") {
        scwin.f_openGridPopup(row, "6");
      }
    }
  } else {
    r = info.rowIndex;
    ds_master.setCellData(r, "rmk1", ds_master.getCellData(r, "holidayYn") == "Y" ? " " : ds_master.getCellData(r, "rmk"));
    ds_master.setCellData(r, "warehouseNm1", ds_master.getCellData(r, "warehouseNm"));
    ds_master.setCellData(r, "bizLongNm1", ds_master.getCellData(r, "bizLongNm"));
    ds_master.setCellData(r, "dmndNo1", ds_master.getCellData(r, "dmndNo"));
    ds_master.setCellData(r, "salePlCoNm1", ds_master.getCellData(r, "salePlCoNm"));
    ds_master.setCellData(r, "mchtOdrNo1", ds_master.getCellData(r, "mchtOdrNo"));
    ds_master.setCellData(r, "odrNo1", ds_master.getCellData(r, "odrNo"));
  }
};
